// ApplyLandResultToExecuteBeadResult maps a LandResult onto an
// ExecuteBeadResult so the execute-bead loop sees the correct final status.
// It is the coordinator-pattern replacement for ApplyLandingToResult.
func ApplyLandResultToExecuteBeadResult(res *ExecuteBeadResult, land *LandResult) {
	if land == nil || res == nil {
		return
	}
	switch land.Status {
	case "landed":
		// Fast-forward or merge commit — either way the target branch now
		// contains the worker's result. ResultRev's own parent is still
		// BaseRev so replay fidelity is preserved.
		res.Outcome = "merged"
		res.Reason = ""
		res.PreserveRef = ""
		if land.Merged {
			res.Reason = "merged onto current tip"
		}
		if land.PushConflict {
			res.Reason = PushConflictReasonPrefix + " " + land.PushError
		} else if land.PushFailed {
			res.Reason = PushFailedReasonPrefix + " " + land.PushError
		}
		if land.CheckoutSyncDeferred {
			detail := "checkout_sync_deferred"
			if len(land.CheckoutSyncDeferredPaths) > 0 {
				detail += ": " + strings.Join(land.CheckoutSyncDeferredPaths, ", ")
			}
			if res.Reason == "" {
				res.Reason = detail
			} else {
				res.Reason += "; " + detail
			}
		}
		// NewTip reflects the ref actually on the target branch (either
		// ResultRev on the ff path or the merge commit SHA on the merge path).
		if land.NewTip != "" {
			// Preserve the implementation rev before rewriting the compat alias.
			if res.ImplementationRev == "" {
				res.ImplementationRev = res.ResultRev
			}

// Default: land the worker's commits on the target branch. When a
// LandingAdvancer is provided (server coordinator / --local coordinator)
// it runs the fetch → (ff or merge) → push sequence serialized per
// projectRoot. When no advancer is provided, LandBeadResult falls back
// to preserving the result under refs/ddx/iterations/ — the interactive
// single-bead CLI path, which intentionally does NOT auto-advance the
// target branch (the operator moves the ref themselves).
if opts.LandingAdvancer != nil {
	land, landErr := opts.LandingAdvancer(res)
	if landErr != nil {
		return nil, fmt.Errorf("land advancer: %w", landErr)
	}
	switch land.Status {
	case "landed":
		landing.Outcome = "merged"
		if land.Merged {
			landing.Reason = "merged onto current tip"
		}
		if land.NewTip != "" {
			res.ResultRev = land.NewTip
		}
		if land.PushFailed {
			landing.Reason = PushFailedReasonPrefix + " " + land.PushError
		}
	case "preserved":
		landing.Outcome = "preserved"
		landing.PreserveRef = land.PreserveRef
		landing.Reason = land.Reason
	case "no-changes":
		landing.Outcome = "no-changes"
		landing.Reason = land.Reason
	default:
		landing.Outcome = "preserved"
		landing.Reason = "unknown land status: " + land.Status
	}
	return landing, nil
}

